"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[8117],{62148:e=>{e.exports=JSON.parse('{"functions":[{"name":"MaxDistance","desc":"Maximum distance in studs the bullet can travel before expiring.\\n`OnHit` fires with a nil `RaycastResult` when this is reached.\\n\\nDefault: `500`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"PhysicsBuilder"}],"function_type":"method","source":{"line":20,"path":"docs/SubBuilders.lua"}},{"name":"MaxSpeed","desc":"Maximum speed in studs per second. When the bullet\'s speed rises above\\nthis value it is terminated. `OnHit` fires with a nil `RaycastResult`.\\n\\nUseful for capping homing missiles or rockets that accelerate indefinitely,\\npreventing them from tunnelling through thin surfaces.\\n\\nDefault: `math.huge` (no cap)","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"PhysicsBuilder"}],"function_type":"method","source":{"line":34,"path":"docs/SubBuilders.lua"}},{"name":"MinSpeed","desc":"Minimum speed in studs per second. When the bullet\'s speed drops below\\nthis value it is terminated. `OnHit` fires with a nil `RaycastResult`.\\n\\nDefault: `1`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"PhysicsBuilder"}],"function_type":"method","source":{"line":45,"path":"docs/SubBuilders.lua"}},{"name":"Gravity","desc":"Gravitational acceleration applied to the bullet. Pass a negative-Y\\nvector for downward gravity.\\n\\nDefault: `Vector3.new(0, -workspace.Gravity, 0)` (read at builder construction time)","params":[{"name":"value","desc":"","lua_type":"Vector3"}],"returns":[{"desc":"","lua_type":"PhysicsBuilder"}],"function_type":"method","source":{"line":56,"path":"docs/SubBuilders.lua"}},{"name":"Acceleration","desc":"Extra constant acceleration layered on top of gravity \u2014 for example,\\nrocket thrust. Wind is applied separately via [Vetra:SetWind] and\\n`WindResponse`, and drag is applied separately via `DragCoefficient`.\\n\\nDefault: `Vector3.zero`","params":[{"name":"value","desc":"","lua_type":"Vector3"}],"returns":[{"desc":"","lua_type":"PhysicsBuilder"}],"function_type":"method","source":{"line":68,"path":"docs/SubBuilders.lua"}},{"name":"RaycastParams","desc":"The `RaycastParams` used for all raycasts during this cast\'s lifetime.\\nThe solver acquires a clone from its internal pool \u2014 the original is\\nnever mutated.\\n\\nDefault: `RaycastParams.new()`","params":[{"name":"value","desc":"","lua_type":"RaycastParams"}],"returns":[{"desc":"","lua_type":"PhysicsBuilder"}],"function_type":"method","source":{"line":80,"path":"docs/SubBuilders.lua"}},{"name":"CastFunction","desc":"Optional custom cast function. Replaces `workspace:Raycast` for every\\nintersection test this bullet performs. Use for `workspace:Spherecast`,\\n`workspace:Blockcast`, or any custom raycast wrapper.\\n\\nSignature: `(origin: Vector3, direction: Vector3, params: RaycastParams) -> RaycastResult?`\\n\\n`direction` is the raw displacement vector for that frame (not a unit vector)\\n\u2014 its length equals the cast distance.\\n\\n:::caution Parallel solver\\n`CastFunction` is **serial-exclusive**. It is silently ignored when using\\n`Vetra.newParallel()` because functions cannot cross Actor boundaries via\\nmessage serialization. Use `Vetra.new()` if you need a custom cast function.\\n:::\\n\\nDefault: `nil` (uses `workspace:Raycast`)","params":[{"name":"value","desc":"","lua_type":"(origin: Vector3, direction: Vector3, params: RaycastParams) -> RaycastResult?"}],"returns":[{"desc":"","lua_type":"PhysicsBuilder"}],"function_type":"method","source":{"line":103,"path":"docs/SubBuilders.lua"}},{"name":"BulletMass","desc":"Mass of the bullet in game units. Used by penetration calculations that\\nmodel momentum transfer \u2014 a heavier bullet retains more speed through\\na thick surface than a lighter one given the same `PenetrationForce` budget.\\n\\nSet to `0` to disable mass-based calculations (the force budget is used\\ndirectly without mass scaling). Also used by VetraNet\'s `impactForce`\\ncalculation: `BulletMass \xd7 velocity.Magnitude`.\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"PhysicsBuilder"}],"function_type":"method","source":{"line":119,"path":"docs/SubBuilders.lua"}},{"name":"Done","desc":"Returns the root [BehaviorBuilder].","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"method","source":{"line":126,"path":"docs/SubBuilders.lua"}}],"properties":[],"types":[],"name":"PhysicsBuilder","desc":"Sub-builder for physics configuration. Opened via [BehaviorBuilder:Physics].\\nCall `:Done()` to return to the root [BehaviorBuilder].","source":{"line":9,"path":"docs/SubBuilders.lua"}}')}}]);